+            let normalized = history.normalized();
+            let trace = sparkline(&normalized);
+            let latest = history.latest().unwrap_or(0.0);
+            (path.as_str(), format!("{path}:{trace}({latest:+.0}B/s)"))
+        })
+        .collect();
+    series.sort_unstable_by(|a, b| a.0.cmp(b.0));
